// ============================================================================
// MATERIAL NORMALIZATION FROM SEED MATERIAL
// ============================================================================

const ZIRO_MATERIAL_MAP: Record<string, string> = {
  'CF-PLA': 'PLA-CF',
  'High Speed PLA': 'PLA-HS',
  'TPU': 'TPU-95A',
  'Gradient TPU': 'TPU-95A',
};

export function getZiroMaterialFromSeed(seedMaterial: string): string {
  return ZIRO_MATERIAL_MAP[seedMaterial] || 'PLA';
}

// ============================================================================
// FINISH TYPE EXTRACTION FROM SEED MATERIAL
// ============================================================================

export function getZiroFinishTypeFromSeed(seedMaterial: string): string {
  const material = seedMaterial.toLowerCase();
  if (material.includes('silk')) return 'Silk';
  if (material.includes('matte')) return 'Matte';
  if (material.includes('gradient')) return 'Gradient';
  if (material.includes('twinkling') || material.includes('diamond')) return 'Sparkle';
  if (material.includes('fluorescent')) return 'Fluorescent';
  if (material.includes('glow')) return 'Glow';
  if (material.includes('translucent')) return 'Translucent';
  if (material.includes('metal')) return 'Shimmer';
  if (material.includes('marble') || material.includes('stone') || material.includes('straw')) return 'Stone';
  if (material.includes('chameleon') || material.includes('iridescent')) return 'Iridescent';
  if (material.includes('stripes')) return 'Multi';
  if (material.includes('tri-color') || material.includes('tricolor')) return 'Multi';
  if (material.includes('firefly') || material.includes('mystical')) return 'Sparkle';
  return 'Standard';
}

// ============================================================================
// COLOR FAMILY EXTRACTION
// ============================================================================

export function getZiroColorFamily(colorHex: string, colorName: string): string {
  const lowerColor = colorName.toLowerCase();
  
  // Direct color name matching
  if (lowerColor.includes('black') || lowerColor.includes('night') || lowerColor.includes('shadow') || lowerColor.includes('zebra')) return 'Black';
  if (lowerColor.includes('white') || lowerColor.includes('snow') || lowerColor.includes('marshmallow') || lowerColor.includes('pure')) return 'White';
  if (lowerColor.includes('gray') || lowerColor.includes('grey') || lowerColor.includes('silver') || lowerColor.includes('iron') || lowerColor.includes('steel')) return 'Gray';
  if (lowerColor.includes('gold') || lowerColor.includes('champagne') || lowerColor.includes('gilded') || lowerColor.includes('brass')) return 'Gold';
  if (lowerColor.includes('bronze') || lowerColor.includes('copper')) return 'Bronze';
  if (lowerColor.includes('brown') || lowerColor.includes('chocolate') || lowerColor.includes('caramel') || lowerColor.includes('earth') || lowerColor.includes('wood')) return 'Brown';
  if (lowerColor.includes('beige') || lowerColor.includes('skin') || lowerColor.includes('peach') || lowerColor.includes('cream') || lowerColor.includes('desert')) return 'Beige';
  if (lowerColor.includes('red') || lowerColor.includes('crimson') || lowerColor.includes('volcano') || lowerColor.includes('lava') || lowerColor.includes('flame') || lowerColor.includes('passionate')) return 'Red';
  if (lowerColor.includes('orange') || lowerColor.includes('ember') || lowerColor.includes('sunrise') || lowerColor.includes('citrus') || lowerColor.includes('harvest')) return 'Orange';
  if (lowerColor.includes('yellow') || lowerColor.includes('lemon') || lowerColor.includes('sunflower') || lowerColor.includes('sunlit') || lowerColor.includes('sunlight') || lowerColor.includes('neon')) return 'Yellow';
  if (lowerColor.includes('green') || lowerColor.includes('forest') || lowerColor.includes('olive') || lowerColor.includes('lime') || lowerColor.includes('spring') || lowerColor.includes('aurora') || lowerColor.includes('matcha') || lowerColor.includes('sprout') || lowerColor.includes('meadow')) return 'Green';
  if (lowerColor.includes('teal') || lowerColor.includes('cyan') || lowerColor.includes('aqua') || lowerColor.includes('turquoise') || lowerColor.includes('mermaid')) return 'Teal';
  if (lowerColor.includes('blue') || lowerColor.includes('ocean') || lowerColor.includes('navy') || lowerColor.includes('sky') || lowerColor.includes('glacier') || lowerColor.includes('ice') || lowerColor.includes('polar') || lowerColor.includes('indigo') || lowerColor.includes('steady')) return 'Blue';
  if (lowerColor.includes('purple') || lowerColor.includes('violet') || lowerColor.includes('lavender') || lowerColor.includes('lilac') || lowerColor.includes('amethyst') || lowerColor.includes('nebula') || lowerColor.includes('mystical')) return 'Purple';
  if (lowerColor.includes('pink') || lowerColor.includes('rose') || lowerColor.includes('magenta') || lowerColor.includes('candy') || lowerColor.includes('fuchsia') || lowerColor.includes('blossom') || lowerColor.includes('romantic') || lowerColor.includes('sweet')) return 'Pink';
  if (lowerColor.includes('rainbow') || lowerColor.includes('spectrum') || lowerColor.includes('prism') || lowerColor.includes('chromatic')) return 'Multi';
  if (lowerColor.includes('transparent') || lowerColor.includes('translucent') || lowerColor.includes('clear') || lowerColor.includes('crystal')) return 'Clear';
  
  // Hex-based fallback
  if (colorHex) {
    const hex = colorHex.replace('#', '');
    const r = parseInt(hex.substring(0, 2), 16);
    const g = parseInt(hex.substring(2, 4), 16);
    const b = parseInt(hex.substring(4, 6), 16);
    const brightness = (r + g + b) / 3;
    
    if (brightness < 50) return 'Black';
    if (brightness > 220 && Math.abs(r - g) < 20 && Math.abs(g - b) < 20) return 'White';
    if (Math.abs(r - g) < 30 && Math.abs(g - b) < 30) return 'Gray';
    if (r > g && r > b) return r > 200 && g > 150 ? 'Orange' : 'Red';
    if (g > r && g > b) return 'Green';
    if (b > r && b > g) return 'Blue';
    if (r > 200 && g > 200) return 'Yellow';
    if (r > 150 && b > 150 && g < 100) return 'Purple';
    if (r > 200 && b > 100 && g < 150) return 'Pink';
  }
  
  return 'Multi';
}

// ============================================================================
// PRODUCT TITLE GENERATION
// ============================================================================

export function generateZiroProductTitle(seed: ZiroProductSeed): string {
  const cleanMaterial = seed.seedMaterial
    .replace('Fast Gradient ', 'Gradient ')
    .replace(' PLA Filament', '')
    .replace(' Filament', '')
    .replace('PLA PRO', 'Translucent PLA');
  
  return `ZIRO ${cleanMaterial} - ${seed.color}`;
}

